member.example:
Bind the Collider providesContacts property using a serialized binder field — the target Collider is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private ColliderProvidesContactsBinder _providesContacts;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _providesContacts;
    }


Bind the Collider providesContacts property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private Collider _collider;
        
        private ColliderProvidesContactsBinder ProvidesContacts =>
            new(_collider);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _providesContacts;
    }
